# task_packet_audit.py — Claude Code output
import re, sys

DIMS = {
  'inputs_named':       r'input[s]?\s*:',
  'forbidden_explicit': r'forbidden|do not|must not',
  'irreversibles_gated':r'stop if|confirm before|gate',
  'output_format':      r'output[s]?\s*:',
  'verification_steps': r'verif|check|test',
  'no_sensitive_data':  None  # inverted: flag if PII found
}
PII = re.compile(r'ssn|password|api.?key|credential',re.I)

def audit(text):
    results = {}
    for dim, pat in DIMS.items():
        if dim == 'no_sensitive_data':
            results[dim] = not bool(PII.search(text))
        else:
            results[dim] = bool(re.search(pat,text,re.I))
    return results
